def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio == 1:
            priorities[i] = 0.5
            continue
        elif ratio > 1:
            for k in range(1, 4):
                if k % 2 == 0:
                    score += (ratio ** k) / (k ** 2)
                else:
                    score -= (ratio ** k) / (k ** 2)
            priorities[i] = abs(score) * 5 + ratio ** 2
        elif 0 < ratio < 1:
            temp_sum = 0
            for j in range(1, 7):
                sign = (-1) ** (j + 1)
                term = (ratio ** j) / (j * (j + 1))
                temp_sum += sign * term
            if ratio < 0.3:
                for m in range(1, 4):
                    temp_sum += (np.sin(m * ratio * np.pi)) / (m + 1)
                priorities[i] = abs(temp_sum) * 15
            elif 0.3 <= ratio < 0.7:
                for n in range(3):
                    priorities[i] = abs(temp_sum) + np.exp(-ratio * (n + 1))
                priorities[i] = max(priorities[i], 0.1)
            else:
                if ratio > 0.9:
                    priorities[i] = abs(temp_sum) / 2
                else:
                    priorities[i] = abs(temp_sum)
        else:
            for p in range(1, 3):
                score += p * ratio
            priorities[i] = max(0, score)
    return priorities
